VALUES ('prng_005', 'parung', 'Ujang Permana', 25, '18-24', 'male', 'Buruh Bangunan / Pekerja Lepas', 'low', 3800000, 900000, '["nongkrong warung","rokok","gorengan","bayar harian"]', 'Kontrakan murah area Parung', '{"priceElasticity":"very_sensitive","decisionFactor":["harga di bawah 15rb","mengenyangkan","tidak perlu jalan jauh","bisa utang/bon"],"preferredChannel":["offline (warung dekat proyek)","pedagang kaki lima"],"weeklyFnBSpend":200000}', '{"values":["solidaritas sesama pekerja","kepraktisan","makan kenyang"],"mediaConsumption":["YouTube","Facebook","TikTok sesekali"],"peerInfluence":"high"}', '{"culturalNote":"Pekerja lepas Parung adalah segmen volume tinggi dengan margin rendah. Mereka mencari tempat makan yang bisa bayar kemudian (bon/utang) dan sangat loyal jika diperlakukan baik.","competitorAwareness":["Warteg","Nasi Bungkus","Gorengan","Mie Instan Rebus"]}');
